module RefModule (
    input [3:0] temperature,
    input reset,
    output reg alert
);
  wire [3:0] _tap_temperature = temperature & {4{1'b1}};

    always @(*) begin
        if (reset) 
            alert = 0;
        else 
            alert = (temperature > 4'b1010) ? 1 : 0; // 10 degrees Celsius in binary
    end
endmodule
